                  la_axis_cur_idx <= la_axis_len - 1'b1;
                  la_axis_val <= read_data1[`hed_start:`hed_end];
                  la_axis_bit <= msb_index(read_data1[`hed_start:`hed_end]) - 1'b1;
                  address1 <= command_tel_addr;
                  mem_execute <= 1;
                  mem_func <= `GET_CONTENTS;
                  state <= READ_INIT;
                end
              end else begin
                la_axis_val <= read_data1[`hed_start:`hed_end];
                la_axis_bit <= 6'd27;
                if (la_next_addr != 0) begin
                  address1 <= la_next_addr;
                  la_next_addr <= 0;
                  mem_execute <= 1;
                  mem_func <= `GET_CONTENTS;
                  state <= SLOT_CHECK_LA;
                end else begin
                  address1 <= command_tel_addr;
                  mem_execute <= 1;
                  mem_func <= `GET_CONTENTS;
                  state <= READ_INIT;
                end
              end
            end else begin
              if (read_data1[`tel_tag] != `CELL) begin
                debug_sig <= 3;
                state <= ERROR;
              end else begin
                la_axis_ptr <= read_data1[`tel_start:`tel_end];
                la_axis_scan_idx <= la_axis_scan_idx + 1'b1;
                state <= LA_SCAN_READ;
              end
            end
          end else begin
            mem_execute <= 0;
            mem_func <=0;
          end
        end

        PREP_TREE: begin
          if(tree_addr[`noun_width-1] == 1) begin
            state <= READ_INIT;
          end
          tree_addr <= tree_addr << 1;
        end

        READ_INIT: begin
          if (mem_ready) begin
            new_val_tag <= read_data1[`hed_tag];
            new_val <= read_data1[`hed_start:`hed_end];
            target_tag <= read_data1[`tel_tag];
            target <= read_data1[`tel_start:`tel_end];

            if(read_data1[`hed_tag] ==`CELL) begin
              address1 <= read_data1[`hed_start:`hed_end];
              mem_func <= `GET_CONTENTS;
              mem_execute <= 1;
              state <= SLOT_CHECK_INDIRECT;
            end else begin 
              if (axis_large) begin
                state <= SLOT_CHECK_LA;
              end else begin
                state <= SLOT_CHECK;
              end
              address1 <= read_data1[`tel_start:`tel_end];
              mem_func <= `GET_CONTENTS;
              mem_execute <= 1;
            end
          end else begin
            mem_execute <= 0;
            mem_func <=0;
          end
        end

        SLOT_CHECK_INDIRECT: begin
          if (mem_ready) begin
            new_val_reg <= read_data1;
            if (axis_large) begin
              state <= SLOT_CHECK_LA;
            end else begin
              state <= SLOT_CHECK;
            end
            address1 <= target[`tel_start:`tel_end];
            mem_func <= `GET_CONTENTS;
            mem_execute <= 1;
            if(read_data1[`tel_start:`tel_end] == `NIL 
            && read_data1[`tel_tag] == `ATOM
            && read_data1[`hed_tag] == `ATOM) begin
              new_val <= read_data1[`hed_start:`hed_end];
              new_val_tag <= read_data1[`hed_tag];
            end
          end else begin
            mem_execute <= 0;
            mem_func <=0;
          end
        end

        SLOT_CHECK: begin
          if (mem_ready) begin
            if ( tree_addr == 28'h8000000) begin
              mem_func <= `SET_CONTENTS;
              address1 <= address1;
              mem_execute <= 1;
              state <= READ_TREE;
              if(new_val_tag == `CELL) begin
                write_data <= new_val_reg;
              end else begin
                write_data <= {
                6'b000000,
                `ATOM,
                `ATOM,
                new_val,
                `NIL};
              end
            end else begin
              if (read_data1[`large_atom_bit]) begin
                if (tree_addr[`noun_width-1] == 0) begin
                  debug_sig <= 1;
                end else begin
                  debug_sig <= 2;
                end
                state <= ERROR;
              end else begin
                if (tree_addr[`noun_width-1] == 0) begin
                  if(tree_addr == 28'h4000000) begin
                    mem_func <= `SET_CONTENTS;
                    address1 <= address1;
                    mem_execute <= 1;
                    write_data <= {
                      read_data1[`execute_bit],
                      5'b00000,
                      new_val_tag,
                      read_data1[`tel_tag],
                      new_val,
                      read_data1[`tel_start:`tel_end]};
                    state <= READ_TREE;
                  end else if(read_data1[`hed_tag] == `CELL) begin
                    address1 <= read_data1[`hed_start:`hed_end];
                    mem_func <= `GET_CONTENTS;
                    mem_execute <= 1;
                    state <= SLOT_CHECK;
                  end else begin
                    debug_sig <= 1;
                    state <= ERROR;
                  end
                end else begin
                  if(tree_addr == 28'hC000000) begin
                    mem_func <= `SET_CONTENTS;
                    address1 <= address1;
                    mem_execute <= 1;
                    write_data <= {
                      read_data1[`execute_bit],
                      5'b00000,
                      read_data1[`hed_tag],
                      new_val_tag,
                      read_data1[`hed_start:`hed_end],
                      new_val};
                    state <= READ_TREE;
                  end else if(read_data1[`tel_tag] == `CELL) begin
                    address1 <= read_data1[`tel_start:`tel_end];
                    mem_func <= `GET_CONTENTS;
                    mem_execute <= 1;
                    state <= SLOT_CHECK;
                  end else begin
                    debug_sig <= 2;
                    state <= ERROR;
                  end
                end
                tree_addr <= tree_addr << 1;
              end
            end
          end else begin
            mem_func <= 0;
            mem_execute <= 0;
          end
        end

        SLOT_CHECK_LA: begin
          if (mem_ready) begin
            if (la_axis_done) begin
              mem_func <= `SET_CONTENTS;
              address1 <= address1;
              mem_execute <= 1;
              state <= READ_TREE;
              if(new_val_tag == `CELL) begin
                write_data <= new_val_reg;
              end else begin
                write_data <= {
                6'b000000,
                `ATOM,
                `ATOM,
                new_val,
                `NIL};
              end
            end else begin
              if (read_data1[`large_atom_bit]) begin
                debug_sig <= 3;
                state <= ERROR;
              end else if (la_axis_val[la_axis_bit] == 1'b0) begin
                if (la_axis_cur_idx == 0 && la_axis_bit == 0
                && read_data1[`hed_tag] == `ATOM) begin
                  mem_func <= `SET_CONTENTS;
                  address1 <= address1;
                  mem_execute <= 1;
                  write_data <= {
                    read_data1[`execute_bit],
                    5'b00000,
                    new_val_tag,
                    read_data1[`tel_tag],
                    new_val,
                    read_data1[`tel_start:`tel_end]};
                  state <= READ_TREE;
                end else if (read_data1[`hed_tag] == `CELL) begin
                  if (la_axis_cur_idx == 0 && la_axis_bit == 0) begin
                    la_axis_done <= 1'b1;
                    address1 <= read_data1[`hed_start:`hed_end];
                    mem_func <= `GET_CONTENTS;
                    mem_execute <= 1;
                    state <= SLOT_CHECK_LA;
                  end else if (la_axis_bit == 0) begin
                    la_axis_cur_idx <= la_axis_cur_idx - 1'b1;
                    la_axis_scan_mode <= 1'b1;
                    la_axis_target_idx <= la_axis_cur_idx - 1'b1;
                    la_axis_scan_idx <= 0;
                    la_axis_ptr <= la_axis_head_ptr;
                    la_next_addr <= read_data1[`hed_start:`hed_end];
                    state <= LA_SCAN_READ;
                  end else begin
                    la_axis_bit <= la_axis_bit - 1'b1;
                    address1 <= read_data1[`hed_start:`hed_end];
                    mem_func <= `GET_CONTENTS;
                    mem_execute <= 1;
                    state <= SLOT_CHECK_LA;
                  end
                end else begin
                  debug_sig <= 1;
                  state <= ERROR;
                end
              end else begin
                if (la_axis_cur_idx == 0 && la_axis_bit == 0
                && read_data1[`tel_tag] == `ATOM) begin
                  mem_func <= `SET_CONTENTS;
                  address1 <= address1;
                  mem_execute <= 1;
                  write_data <= {
                    read_data1[`execute_bit],
                    5'b00000,
                    read_data1[`hed_tag],
                    new_val_tag,
                    read_data1[`hed_start:`hed_end],
                    new_val};
                  state <= READ_TREE;
                end else if (read_data1[`tel_tag] == `CELL) begin
                  if (la_axis_cur_idx == 0 && la_axis_bit == 0) begin
                    la_axis_done <= 1'b1;
                    address1 <= read_data1[`tel_start:`tel_end];
                    mem_func <= `GET_CONTENTS;
                    mem_execute <= 1;
                    state <= SLOT_CHECK_LA;
                  end else if (la_axis_bit == 0) begin
                    la_axis_cur_idx <= la_axis_cur_idx - 1'b1;
                    la_axis_scan_mode <= 1'b1;
                    la_axis_target_idx <= la_axis_cur_idx - 1'b1;
                    la_axis_scan_idx <= 0;
                    la_axis_ptr <= la_axis_head_ptr;
                    la_next_addr <= read_data1[`tel_start:`tel_end];
                    state <= LA_SCAN_READ;
                  end else begin
                    la_axis_bit <= la_axis_bit - 1'b1;
                    address1 <= read_data1[`tel_start:`tel_end];
                    mem_func <= `GET_CONTENTS;
                    mem_execute <= 1;
                    state <= SLOT_CHECK_LA;
                  end
                end else begin
                  debug_sig <= 2;
                  state <= ERROR;
                end
              end
            end
          end else begin
            mem_func <= 0;
            mem_execute <= 0;
          end
        end

        READ_TREE: begin
          if (mem_ready) begin
            mem_func <= `GET_CONTENTS;
            address1 <= target ;
            mem_execute <= 1;
            state <= WRITE_ROOT;
          end else begin
            mem_func <= 0;
            mem_execute <= 0;
          end
        end

        WRITE_ROOT: begin
          if (mem_ready) begin
            mem_func <= `SET_CONTENTS;
            address1 <= edit_address;
            mem_execute <= 1;
            write_data <= read_data1;
            state <= DONE;
          end else begin
            mem_func <= 0;
            mem_execute <= 0;
          end
        end

        DONE: begin
          if (mem_ready) begin
            edit_return_sys_func <= `SYS_FUNC_READ;
            edit_return_state <= `SYS_READ_INIT;
            is_finished_reg <= 1;
            state <= PAUSE;
          end else begin
            mem_func <= 0;
            mem_execute <= 0;
          end
        end
        PAUSE: begin
          is_finished_reg <=0;
          if (edit_start == `MUX_EDIT) state<= INIT;
        end

        ERROR: begin
          mem_execute <= 0;
          case (debug_sig)
            8'h1: edit_error <= `ERROR_INVALID_SLOT_HED;
            8'h2: edit_error <= `ERROR_INVALID_SLOT_TEL;
            default: edit_error <= `ERROR_INVALID_SLOT;
          endcase
          edit_return_sys_func <= `SYS_FUNC_EXECUTE;
          edit_return_state <= `SYS_EXECUTE_ERROR;
          is_finished_reg <= 1;
        end
      endcase
    end
  end
endmodule

